class Solution:
    def distributeCandies(self, n: int, limit: int) -> int:
        total = 0
        lo_a = max(0, n - 2 * limit)
        hi_a = min(limit, n)
        for a in range(lo_a, hi_a + 1):
            rem = n - a
            lo_b = max(0, rem - limit)
            hi_b = min(limit, rem)
            if hi_b >= lo_b:
                total += hi_b - lo_b + 1
        return total

