class Solution:
    def distributeCandies(self, n: int, limit: int) -> int:
        def uncapped(x):
            if x < 0:
                return 0
            return (x + 1) * (x + 2) // 2
        step = limit + 1
        return (uncapped(n) - 3 * uncapped(n - step) + 3 * uncapped(n - 2 * step) - uncapped(n - 3 * step))

